import{_ as t,o as a,c as i,an as r}from"./chunks/framework.BftF_wGS.js";const f=JSON.parse('{"title":"Charter and status","description":"","frontmatter":{},"headers":[],"relativePath":"tools/index.md","filePath":"tools/index.md","lastUpdated":null}'),o={name:"tools/index.md"};function s(d,e,l,n,h,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="charter" tabindex="-1">Charter and status <a class="header-anchor" href="#charter" aria-label="Permalink to &quot;Charter and status {#charter}&quot;">​</a></h1><p>EpiAwareADTools is the EpiAware org&#39;s shared home for AD-safety machinery and AD workarounds. It exists so the same fix is not duplicated across packages, and so each fix has one documented owner.</p><p>Every entry here is a fix we host while we try to fix the underlying problem upstream. Each is documented with the upstream package or issue where it ideally belongs and the condition under which it is deleted. When an upstream fix lands, the matching entry is removed rather than left to rot.</p><h2 id="What-lives-here" tabindex="-1">What lives here <a class="header-anchor" href="#What-lives-here" aria-label="Permalink to &quot;What lives here {#What-lives-here}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Tool</th><th style="text-align:right;">What it does</th><th style="text-align:right;">Upstream target</th><th style="text-align:right;">Deletion condition</th></tr></thead><tbody><tr><td style="text-align:right;"><a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.primal"><code>primal</code></a> / <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.primal_distribution"><code>primal_distribution</code></a></td><td style="text-align:right;">Strip an AD wrapper from a scalar or a distribution&#39;s parameters, so a non-differentiable hyperparameter stays off the AD path</td><td style="text-align:right;">No single owner; a per-backend &quot;stop gradient&quot; primitive</td><td style="text-align:right;">A shared stop-gradient primitive covering ForwardDiff, ReverseDiff, Enzyme, and Mooncake</td></tr><tr><td style="text-align:right;"><a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.cdf_ad_safe"><code>cdf_ad_safe</code></a>, <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.logcdf_ad_safe"><code>logcdf_ad_safe</code></a>, <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.ccdf_ad_safe"><code>ccdf_ad_safe</code></a>, <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.logccdf_ad_safe"><code>logccdf_ad_safe</code></a>, <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#EpiAwareADTools.pdf_ad_safe"><code>pdf_ad_safe</code></a></td><td style="text-align:right;">Extension-point wrappers whose <code>Gamma</code> methods stay differentiable in shape/scale</td><td style="text-align:right;"><code>Distributions.jl</code> Gamma CDF/log-CDF differentiable in its parameters</td><td style="text-align:right;"><code>cdf(::Gamma)</code> and <code>logcdf(::Gamma)</code> differentiable upstream on the supported backends</td></tr><tr><td style="text-align:right;">Gamma-CDF derivative (<code>_gamma_cdf</code> and its rules)</td><td style="text-align:right;">Analytic shape/scale/point partials for <code>P(k, x/θ)</code></td><td style="text-align:right;">Differentiable <code>gamma_inc</code> in <code>SpecialFunctions.jl</code> (<a href="https://github.com/JuliaMath/SpecialFunctions.jl/issues/531" target="_blank" rel="noreferrer">issue #531</a>)</td><td style="text-align:right;"><code>SpecialFunctions.gamma_inc</code> carries a complete <code>ChainRule</code> (the shape partial included)</td></tr></tbody></table><h2 id="What-does-not-live-here" tabindex="-1">What does not live here <a class="header-anchor" href="#What-does-not-live-here" aria-label="Permalink to &quot;What does not live here {#What-does-not-live-here}&quot;">​</a></h2><p>The Gauss-Legendre quadrature layer that ConvolvedDistributions.jl uses is out of scope for now. It is a candidate future resident if a second package needs it, but it is not an AD workaround, so it stays where it is used until then.</p><h2 id="How-to-read-each-page" tabindex="-1">How to read each page <a class="header-anchor" href="#How-to-read-each-page" aria-label="Permalink to &quot;How to read each page {#How-to-read-each-page}&quot;">​</a></h2><p>Each tool family has its own page under this section. A page states the problem the tool works around, shows the public surface, and points at the upstream target so a reader can check whether the workaround is still needed. The <a href="/EpiAwareADTools.jl/previews/PR6/lib/public#public-api">Public API</a> and <a href="/EpiAwareADTools.jl/previews/PR6/lib/internals#Internal-Documentation">Internal API</a> reference pages carry the full docstrings.</p>',9)])])}const u=t(o,[["render",s]]);export{f as __pageData,u as default};
